import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export const LoginPage = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      // ✅ Trim input to avoid hidden space issues
      const cleanUsername = username.trim();
      const cleanPassword = password.trim();

      // ✅ Debug log (remove later)
      console.log("Sending login:", cleanUsername, cleanPassword);

      await login(cleanUsername, cleanPassword);

      navigate('/dashboard');
    } catch (err) {
      console.error("Login error:", err); // ✅ debug log

      setError(
        err?.response?.data?.message ||
        err?.message ||
        'Invalid username or password'
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-600 to-blue-800 flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        <div className="bg-white rounded-lg shadow-2xl p-8">

          {/* Header */}
          <div className="text-center mb-8">
            <h1 className="text-4xl font-bold text-gray-800 mb-2">Task Dashboard</h1>
            <p className="text-gray-600">Role-Based Task Management System</p>
          </div>

          {/* Form */}
          <form onSubmit={handleSubmit}>
            {error && (
              <div className="mb-4 p-3 bg-red-100 border border-red-400 text-red-700 rounded">
                {error}
              </div>
            )}

            <div className="mb-4">
              <label className="block text-gray-700 font-semibold mb-2">Username</label>
              <input
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                placeholder="Enter username"
                required   // ✅ small improvement (no logic change)
              />
            </div>

            <div className="mb-6">
              <label className="block text-gray-700 font-semibold mb-2">Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                placeholder="Enter password"
                required   // ✅ small improvement
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-blue-600 text-white font-semibold py-2 rounded-lg hover:bg-blue-700 transition disabled:opacity-50"
            >
              {loading ? 'Logging in...' : 'Login'}
            </button>
          </form>

          {/* Demo Credentials */}
          <div className="mt-8 pt-6 border-t border-gray-200">
            <p className="text-gray-700 font-semibold mb-3">📝 Demo Credentials:</p>
            <div className="bg-gray-50 p-3 rounded mb-2">
              <p className="text-sm">
                <span className="font-semibold">Manager:</span> manager1 / 123
              </p>
            </div>
            <div className="bg-gray-50 p-3 rounded">
              <p className="text-sm">
                <span className="font-semibold">Employee:</span> emp1 / 123
              </p>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
};
